import{_ as l,o,c as i,ae as c}from"./chunks/framework.C7FLYIpo.js";const h=JSON.parse('{"title":"테스트","description":"테스트 킷: 유닛/e2e/라이브 스위트, Docker 러너, 각 테스트 범위","frontmatter":{"title":"테스트","description":"테스트 킷: 유닛/e2e/라이브 스위트, Docker 러너, 각 테스트 범위"},"headers":[],"relativePath":"help/testing.md","filePath":"help/testing.md","lastUpdated":null}'),d={name:"help/testing.md"};function t(a,e,s,n,r,p){return o(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="테스트" tabindex="-1">테스트 <a class="header-anchor" href="#테스트" aria-label="Permalink to &quot;테스트&quot;">​</a></h1><p>OpenClaw에는 세 가지 Vitest 스위트(유닛/통합, e2e, 라이브)와 소규모 Docker 러너 세트가 있습니다.</p><p>이 문서는 &quot;테스트 방법&quot; 가이드입니다:</p><ul><li>각 스위트의 범위 (의도적으로 다루지 않는 것 포함)</li><li>일반 워크플로우(로컬, 푸시 전, 디버깅)에 실행할 명령</li><li>라이브 테스트가 자격 증명을 검색하고 모델/프로바이더를 선택하는 방법</li><li>실제 모델/프로바이더 문제에 대한 회귀 테스트 추가 방법</li></ul><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><p>대부분의 날:</p><ul><li>전체 게이트(푸시 전 예상): <code>pnpm build &amp;&amp; pnpm check &amp;&amp; pnpm test</code></li><li>여유 있는 머신에서 더 빠른 로컬 전체 스위트 실행: <code>pnpm test:max</code></li><li>직접 Vitest 감시 루프: <code>pnpm test:watch</code></li><li>직접 파일 대상 지정이 이제 extension/channel 경로도 라우팅합니다: <code>pnpm test extensions/discord/src/monitor/message-handler.preflight.test.ts</code></li><li>Docker 기반 QA 사이트: <code>pnpm qa:lab:up</code></li></ul><p>테스트를 수정하거나 추가적인 확인이 필요한 경우:</p><ul><li>커버리지 게이트: <code>pnpm test:coverage</code></li><li>E2E 스위트: <code>pnpm test:e2e</code></li></ul><p>실제 프로바이더/모델 디버깅 시 (실제 자격 증명 필요):</p><ul><li>라이브 스위트 (모델 + 게이트웨이 도구/이미지 프로브): <code>pnpm test:live</code></li><li>하나의 라이브 파일 조용히 대상 지정: <code>pnpm test:live -- src/agents/models.profiles.live.test.ts</code></li></ul><p>팁: 실패한 케이스 하나만 필요한 경우 아래에 설명된 허용 목록 환경 변수를 통해 라이브 테스트를 좁히십시오.</p><h2 id="테스트-스위트-어디서-무엇이-실행되는가" tabindex="-1">테스트 스위트 (어디서 무엇이 실행되는가) <a class="header-anchor" href="#테스트-스위트-어디서-무엇이-실행되는가" aria-label="Permalink to &quot;테스트 스위트 (어디서 무엇이 실행되는가)&quot;">​</a></h2><p>스위트를 &quot;증가하는 현실성&quot; (그리고 증가하는 불안정성/비용)으로 생각하십시오:</p><h3 id="유닛-통합-기본" tabindex="-1">유닛 / 통합 (기본) <a class="header-anchor" href="#유닛-통합-기본" aria-label="Permalink to &quot;유닛 / 통합 (기본)&quot;">​</a></h3><ul><li>명령: <code>pnpm test</code></li><li>구성: 기존 범위 지정 Vitest 프로젝트에 대한 10개 순차 샤드 실행 (<code>vitest.full-*.config.ts</code>)</li><li>파일: <code>src/**/*.test.ts</code>, <code>packages/**/*.test.ts</code>, <code>test/**/*.test.ts</code> 아래의 핵심/유닛 인벤토리와 <code>vitest.unit.config.ts</code>가 다루는 허용된 <code>ui</code> 노드 테스트</li><li>범위: <ul><li>순수 유닛 테스트</li><li>인프로세스 통합 테스트 (게이트웨이 인증, 라우팅, 도구, 파싱, 구성)</li><li>알려진 버그에 대한 결정론적 회귀 테스트</li></ul></li><li>기대: <ul><li>CI에서 실행</li><li>실제 키 불필요</li><li>빠르고 안정적이어야 함</li></ul></li><li>프로젝트 참고: <ul><li>대상 없는 <code>pnpm test</code>는 이제 하나의 거대한 네이티브 루트 프로젝트 프로세스 대신 11개의 소규모 샤드 구성(<code>core-unit-src</code>, <code>core-unit-security</code>, <code>core-unit-ui</code>, <code>core-unit-support</code>, <code>core-support-boundary</code>, <code>core-contracts</code>, <code>core-bundled</code>, <code>core-runtime</code>, <code>agentic</code>, <code>auto-reply</code>, <code>extensions</code>)을 실행합니다. 이는 부하가 높은 머신에서 최대 RSS를 줄이고 auto-reply/extension 작업이 관련 없는 스위트를 굶기지 않도록 합니다.</li><li><code>pnpm test --watch</code>는 멀티 샤드 감시 루프가 실용적이지 않기 때문에 여전히 네이티브 루트 <code>vitest.config.ts</code> 프로젝트 그래프를 사용합니다.</li><li><code>pnpm test</code>, <code>pnpm test:watch</code>, <code>pnpm test:perf:imports</code>는 명시적 파일/디렉토리 대상을 먼저 범위 지정 레인을 통해 라우팅합니다.</li><li><code>pnpm test:changed</code>는 변경된 git 경로가 더 작은 스위트에 깔끔하게 매핑될 때 범위 지정 레인을 통해 확장합니다.</li></ul></li></ul><h3 id="e2e-게이트웨이-스모크" tabindex="-1">E2E (게이트웨이 스모크) <a class="header-anchor" href="#e2e-게이트웨이-스모크" aria-label="Permalink to &quot;E2E (게이트웨이 스모크)&quot;">​</a></h3><ul><li>명령: <code>pnpm test:e2e</code></li><li>구성: <code>vitest.e2e.config.ts</code></li><li>파일: <code>src/**/*.e2e.test.ts</code>, <code>test/**/*.e2e.test.ts</code></li><li>런타임 기본값: <ul><li><code>isolate: false</code>로 Vitest <code>threads</code> 사용</li><li>적응형 워커 사용 (CI: 최대 2, 로컬: 기본 1)</li><li>기본적으로 콘솔 I/O 오버헤드 감소를 위해 자동 모드로 실행</li></ul></li><li>유용한 재정의: <ul><li><code>OPENCLAW_E2E_WORKERS=&amp;lt;n&amp;gt;</code>: 워커 수 강제 지정 (최대 16)</li><li><code>OPENCLAW_E2E_VERBOSE=1</code>: 상세 콘솔 출력 재활성화</li></ul></li><li>범위: <ul><li>멀티 인스턴스 게이트웨이 엔드 투 엔드 동작</li><li>WebSocket/HTTP 인터페이스, 노드 페어링 및 더 무거운 네트워킹</li></ul></li><li>기대: <ul><li>CI에서 실행 (파이프라인에서 활성화된 경우)</li><li>실제 키 불필요</li><li>유닛 테스트보다 움직임이 더 많음 (더 느릴 수 있음)</li></ul></li></ul><h3 id="e2e-openshell-백엔드-스모크" tabindex="-1">E2E: OpenShell 백엔드 스모크 <a class="header-anchor" href="#e2e-openshell-백엔드-스모크" aria-label="Permalink to &quot;E2E: OpenShell 백엔드 스모크&quot;">​</a></h3><ul><li>명령: <code>pnpm test:e2e:openshell</code></li><li>파일: <code>test/openshell-sandbox.e2e.test.ts</code></li><li>범위: <ul><li>Docker를 통해 호스트에서 격리된 OpenShell 게이트웨이 시작</li><li>임시 로컬 Dockerfile에서 샌드박스 생성</li><li>실제 <code>sandbox ssh-config</code> + SSH exec를 통해 OpenClaw의 OpenShell 백엔드 실행</li><li>샌드박스 fs 브리지를 통해 원격 정규 파일시스템 동작 확인</li></ul></li><li>기대: <ul><li>선택 사항만; 기본 <code>pnpm test:e2e</code> 실행의 일부 아님</li><li>로컬 <code>openshell</code> CLI와 작동하는 Docker 데몬 필요</li><li>격리된 <code>HOME</code> / <code>XDG_CONFIG_HOME</code> 사용 후 테스트 게이트웨이와 샌드박스 삭제</li></ul></li><li>유용한 재정의: <ul><li><code>OPENCLAW_E2E_OPENSHELL=1</code>: 광범위한 e2e 스위트를 수동으로 실행할 때 테스트 활성화</li><li><code>OPENCLAW_E2E_OPENSHELL_COMMAND=/path/to/openshell</code>: 기본값이 아닌 CLI 바이너리 또는 래퍼 스크립트 지정</li></ul></li></ul><h3 id="라이브-실제-프로바이더-실제-모델" tabindex="-1">라이브 (실제 프로바이더 + 실제 모델) <a class="header-anchor" href="#라이브-실제-프로바이더-실제-모델" aria-label="Permalink to &quot;라이브 (실제 프로바이더 + 실제 모델)&quot;">​</a></h3><ul><li>명령: <code>pnpm test:live</code></li><li>구성: <code>vitest.live.config.ts</code></li><li>파일: <code>src/**/*.live.test.ts</code></li><li>기본값: <code>pnpm test:live</code>로 <strong>활성화</strong> (<code>OPENCLAW_LIVE_TEST=1</code> 설정)</li><li>범위: <ul><li>&quot;이 프로바이더/모델이 오늘 실제 자격 증명으로 실제로 작동하는가?&quot;</li><li>프로바이더 형식 변경, 도구 호출 특이점, 인증 문제 및 속도 제한 동작 포착</li></ul></li><li>기대: <ul><li>설계상 CI 안정성 없음 (실제 네트워크, 실제 프로바이더 정책, 할당량, 중단)</li><li>비용 발생 / 속도 제한 사용</li><li>&quot;모든 것&quot;이 아닌 좁혀진 하위 집합 실행 선호</li></ul></li><li>라이브 실행은 누락된 API 키를 가져오기 위해 <code>~/.profile</code>을 소싱합니다.</li><li>기본적으로 라이브 실행은 여전히 <code>HOME</code>을 격리하고 구성/인증 자료를 임시 테스트 홈으로 복사합니다.</li><li>실제 홈 디렉토리를 사용하려면 <code>OPENCLAW_LIVE_USE_REAL_HOME=1</code>만 설정하십시오.</li><li>API 키 교체 (프로바이더별): <code>*_API_KEYS</code>를 쉼표/세미콜론 형식 또는 <code>*_API_KEY_1</code>, <code>*_API_KEY_2</code>로 설정하십시오.</li></ul><h2 id="어떤-스위트를-실행해야-하는가" tabindex="-1">어떤 스위트를 실행해야 하는가? <a class="header-anchor" href="#어떤-스위트를-실행해야-하는가" aria-label="Permalink to &quot;어떤 스위트를 실행해야 하는가?&quot;">​</a></h2><p>이 결정 표를 사용하십시오:</p><ul><li>로직/테스트 편집: <code>pnpm test</code> 실행 (많이 변경한 경우 <code>pnpm test:coverage</code>도)</li><li>게이트웨이 네트워킹 / WS 프로토콜 / 페어링 수정: <code>pnpm test:e2e</code> 추가</li><li>&quot;내 봇이 다운되었음&quot; / 프로바이더별 실패 / 도구 호출 디버깅: 좁혀진 <code>pnpm test:live</code> 실행</li></ul><h2 id="라이브-android-노드-기능-스윕" tabindex="-1">라이브: Android 노드 기능 스윕 <a class="header-anchor" href="#라이브-android-노드-기능-스윕" aria-label="Permalink to &quot;라이브: Android 노드 기능 스윕&quot;">​</a></h2><ul><li>테스트: <code>src/gateway/android-node.capabilities.live.test.ts</code></li><li>스크립트: <code>pnpm android:test:integration</code></li><li>목표: 연결된 Android 노드가 현재 광고하는 <strong>모든 명령</strong>을 호출하고 명령 계약 동작을 확인합니다.</li><li>범위: <ul><li>사전 조건/수동 설정 (스위트는 앱을 설치/실행/페어링하지 않음)</li><li>선택된 Android 노드에 대한 명령별 게이트웨이 <code>node.invoke</code> 유효성 검사</li></ul></li><li>필수 사전 설정: <ul><li>Android 앱이 게이트웨이에 이미 연결 + 페어링됨</li><li>앱이 포그라운드 상태 유지</li><li>통과를 예상하는 기능에 권한/캡처 동의가 부여됨</li></ul></li><li>선택적 대상 재정의: <ul><li><code>OPENCLAW_ANDROID_NODE_ID</code> 또는 <code>OPENCLAW_ANDROID_NODE_NAME</code></li><li><code>OPENCLAW_ANDROID_GATEWAY_URL</code> / <code>OPENCLAW_ANDROID_GATEWAY_TOKEN</code> / <code>OPENCLAW_ANDROID_GATEWAY_PASSWORD</code></li></ul></li><li>전체 Android 설정 세부 정보: <a href="/openclaw-docs-ko/platforms/android">Android 앱</a></li></ul><h2 id="라이브-모델-스모크-프로필-키" tabindex="-1">라이브: 모델 스모크 (프로필 키) <a class="header-anchor" href="#라이브-모델-스모크-프로필-키" aria-label="Permalink to &quot;라이브: 모델 스모크 (프로필 키)&quot;">​</a></h2><p>라이브 테스트는 실패를 격리하기 위해 두 레이어로 분리됩니다:</p><ul><li>&quot;직접 모델&quot;은 프로바이더/모델이 주어진 키로 전혀 응답할 수 있는지 알려줍니다.</li><li>&quot;게이트웨이 스모크&quot;는 해당 모델에 대해 전체 게이트웨이+에이전트 파이프라인이 작동하는지 알려줍니다 (세션, 히스토리, 도구, 샌드박스 정책 등).</li></ul><h3 id="레이어-1-직접-모델-완성-게이트웨이-없음" tabindex="-1">레이어 1: 직접 모델 완성 (게이트웨이 없음) <a class="header-anchor" href="#레이어-1-직접-모델-완성-게이트웨이-없음" aria-label="Permalink to &quot;레이어 1: 직접 모델 완성 (게이트웨이 없음)&quot;">​</a></h3><ul><li>테스트: <code>src/agents/models.profiles.live.test.ts</code></li><li>목표: <ul><li>발견된 모델 열거</li><li><code>getApiKeyForModel</code>을 사용하여 자격 증명이 있는 모델 선택</li><li>모델당 소규모 완성 실행 (필요한 경우 대상 회귀 포함)</li></ul></li><li>활성화 방법: <ul><li><code>pnpm test:live</code> (또는 Vitest를 직접 호출하는 경우 <code>OPENCLAW_LIVE_TEST=1</code>)</li></ul></li><li>모델 선택 방법: <ul><li><code>OPENCLAW_LIVE_MODELS=modern</code>: 현대 허용 목록 실행</li><li><code>OPENCLAW_LIVE_MODELS=all</code>: <code>modern</code>의 별칭</li><li>또는 <code>OPENCLAW_LIVE_MODELS=&quot;openai/gpt-5.4,anthropic/claude-opus-4-6,...&quot;</code> (쉼표 허용 목록)</li></ul></li><li>프로바이더 선택 방법: <ul><li><code>OPENCLAW_LIVE_PROVIDERS=&quot;google,google-antigravity,google-gemini-cli&quot;</code> (쉼표 허용 목록)</li></ul></li></ul><h3 id="레이어-2-게이트웨이-개발-에이전트-스모크" tabindex="-1">레이어 2: 게이트웨이 + 개발 에이전트 스모크 <a class="header-anchor" href="#레이어-2-게이트웨이-개발-에이전트-스모크" aria-label="Permalink to &quot;레이어 2: 게이트웨이 + 개발 에이전트 스모크&quot;">​</a></h3><ul><li>테스트: <code>src/gateway/gateway-models.profiles.live.test.ts</code></li><li>목표: <ul><li>인프로세스 게이트웨이 시작</li><li><code>agent:dev:*</code> 세션 생성/패치 (실행당 모델 재정의)</li><li>키가 있는 모델 반복 및 확인: <ul><li>&quot;의미 있는&quot; 응답 (도구 없음)</li><li>실제 도구 호출 작동 (읽기 프로브)</li><li>선택적 추가 도구 프로브 (exec+읽기 프로브)</li><li>OpenAI 회귀 경로 (도구 호출 전용 → 후속 조치)</li></ul></li></ul></li><li>활성화 방법: <ul><li><code>pnpm test:live</code> (또는 Vitest를 직접 호출하는 경우 <code>OPENCLAW_LIVE_TEST=1</code>)</li></ul></li><li>모델 선택 방법: <ul><li>기본값: 현대 허용 목록</li><li><code>OPENCLAW_LIVE_GATEWAY_MODELS=all</code>: 현대 허용 목록의 별칭</li><li>또는 <code>OPENCLAW_LIVE_GATEWAY_MODELS=&quot;provider/model&quot;</code> (또는 쉼표 목록)으로 좁히기</li></ul></li></ul><h2 id="자격-증명-커밋하지-마십시오" tabindex="-1">자격 증명 (커밋하지 마십시오) <a class="header-anchor" href="#자격-증명-커밋하지-마십시오" aria-label="Permalink to &quot;자격 증명 (커밋하지 마십시오)&quot;">​</a></h2><p>라이브 테스트는 CLI와 동일한 방식으로 자격 증명을 검색합니다:</p><ul><li><p>CLI가 작동하면 라이브 테스트도 동일한 키를 찾아야 합니다.</p></li><li><p>라이브 테스트에서 &quot;자격 증명 없음&quot;이라고 하면 <code>openclaw models list</code> / 모델 선택 디버깅과 동일한 방법으로 디버그하십시오.</p></li><li><p>에이전트별 인증 프로필: <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/agent/auth-profiles.json</code></p></li><li><p>구성: <code>~/.openclaw/openclaw.json</code> (또는 <code>OPENCLAW_CONFIG_PATH</code>)</p></li><li><p>레거시 상태 디렉토리: <code>~/.openclaw/credentials/</code></p></li></ul><h2 id="docker-러너-선택적-linux에서-작동-확인" tabindex="-1">Docker 러너 (선택적 &quot;Linux에서 작동&quot; 확인) <a class="header-anchor" href="#docker-러너-선택적-linux에서-작동-확인" aria-label="Permalink to &quot;Docker 러너 (선택적 &quot;Linux에서 작동&quot; 확인)&quot;">​</a></h2><p>Docker 러너는 두 가지 버킷으로 나뉩니다:</p><ul><li>라이브 모델 러너: <code>test:docker:live-models</code>와 <code>test:docker:live-gateway</code>는 리포지토리 Docker 이미지 내에서만 매칭 프로필 키 라이브 파일을 실행합니다.</li><li>컨테이너 스모크 러너: <code>test:docker:openwebui</code>, <code>test:docker:onboard</code>, <code>test:docker:gateway-network</code>, <code>test:docker:mcp-channels</code>, <code>test:docker:plugins</code>는 하나 이상의 실제 컨테이너를 부팅하고 더 높은 수준의 통합 경로를 확인합니다.</li></ul><p>Docker 러너 명령:</p><ul><li>직접 모델: <code>pnpm test:docker:live-models</code> (스크립트: <code>scripts/test-live-models-docker.sh</code>)</li><li>ACP 바인드 스모크: <code>pnpm test:docker:live-acp-bind</code> (스크립트: <code>scripts/test-live-acp-bind-docker.sh</code>)</li><li>CLI 백엔드 스모크: <code>pnpm test:docker:live-cli-backend</code> (스크립트: <code>scripts/test-live-cli-backend-docker.sh</code>)</li><li>게이트웨이 + 개발 에이전트: <code>pnpm test:docker:live-gateway</code> (스크립트: <code>scripts/test-live-gateway-models-docker.sh</code>)</li><li>Open WebUI 라이브 스모크: <code>pnpm test:docker:openwebui</code> (스크립트: <code>scripts/e2e/openwebui-docker.sh</code>)</li><li>온보딩 마법사 (TTY, 전체 스캐폴딩): <code>pnpm test:docker:onboard</code> (스크립트: <code>scripts/e2e/onboard-docker.sh</code>)</li><li>게이트웨이 네트워킹 (두 개의 컨테이너, WS 인증 + 상태): <code>pnpm test:docker:gateway-network</code> (스크립트: <code>scripts/e2e/gateway-network-docker.sh</code>)</li><li>MCP 채널 브리지: <code>pnpm test:docker:mcp-channels</code> (스크립트: <code>scripts/e2e/mcp-channels-docker.sh</code>)</li><li>플러그인 (설치 스모크 + <code>/plugin</code> 별칭 + Claude 번들 재시작 의미론): <code>pnpm test:docker:plugins</code> (스크립트: <code>scripts/e2e/plugins-docker.sh</code>)</li></ul><p>유용한 환경 변수:</p><ul><li><code>OPENCLAW_CONFIG_DIR=...</code> (기본값: <code>~/.openclaw</code>) <code>/home/node/.openclaw</code>에 마운트됨</li><li><code>OPENCLAW_WORKSPACE_DIR=...</code> (기본값: <code>~/.openclaw/workspace</code>) <code>/home/node/.openclaw/workspace</code>에 마운트됨</li><li><code>OPENCLAW_PROFILE_FILE=...</code> (기본값: <code>~/.profile</code>) <code>/home/node/.profile</code>에 마운트되고 테스트 실행 전에 소싱됨</li><li><code>OPENCLAW_DOCKER_CLI_TOOLS_DIR=...</code> (기본값: <code>~/.cache/openclaw/docker-cli-tools</code>) Docker 내부에 캐시된 CLI 설치를 위해 <code>/home/node/.npm-global</code>에 마운트됨</li></ul><h2 id="문서-정상-확인" tabindex="-1">문서 정상 확인 <a class="header-anchor" href="#문서-정상-확인" aria-label="Permalink to &quot;문서 정상 확인&quot;">​</a></h2><p>문서 편집 후 문서 확인 실행: <code>pnpm check:docs</code>. 인페이지 헤딩 확인이 필요한 경우 전체 Mintlify 앵커 유효성 검사 실행: <code>pnpm docs:check-links:anchors</code>.</p><h2 id="계약-테스트-플러그인-및-채널-형태" tabindex="-1">계약 테스트 (플러그인 및 채널 형태) <a class="header-anchor" href="#계약-테스트-플러그인-및-채널-형태" aria-label="Permalink to &quot;계약 테스트 (플러그인 및 채널 형태)&quot;">​</a></h2><p>계약 테스트는 등록된 모든 플러그인과 채널이 인터페이스 계약을 준수하는지 확인합니다.</p><h3 id="명령" tabindex="-1">명령 <a class="header-anchor" href="#명령" aria-label="Permalink to &quot;명령&quot;">​</a></h3><ul><li>모든 계약: <code>pnpm test:contracts</code></li><li>채널 계약만: <code>pnpm test:contracts:channels</code></li><li>프로바이더 계약만: <code>pnpm test:contracts:plugins</code></li></ul><h3 id="채널-계약" tabindex="-1">채널 계약 <a class="header-anchor" href="#채널-계약" aria-label="Permalink to &quot;채널 계약&quot;">​</a></h3><p><code>src/channels/plugins/contracts/*.contract.test.ts</code>에 위치:</p><ul><li><strong>plugin</strong> - 기본 플러그인 형태 (id, name, 기능)</li><li><strong>setup</strong> - 설정 마법사 계약</li><li><strong>session-binding</strong> - 세션 바인딩 동작</li><li><strong>outbound-payload</strong> - 메시지 페이로드 구조</li><li><strong>inbound</strong> - 인바운드 메시지 처리</li><li><strong>actions</strong> - 채널 작업 핸들러</li><li><strong>threading</strong> - 스레드 ID 처리</li><li><strong>directory</strong> - 디렉토리/로스터 API</li><li><strong>group-policy</strong> - 그룹 정책 시행</li></ul><h3 id="프로바이더-계약" tabindex="-1">프로바이더 계약 <a class="header-anchor" href="#프로바이더-계약" aria-label="Permalink to &quot;프로바이더 계약&quot;">​</a></h3><p><code>src/plugins/contracts/*.contract.test.ts</code>에 위치:</p><ul><li><strong>auth</strong> - 인증 흐름 계약</li><li><strong>catalog</strong> - 모델 카탈로그 API</li><li><strong>discovery</strong> - 플러그인 검색</li><li><strong>loader</strong> - 플러그인 로딩</li><li><strong>runtime</strong> - 프로바이더 런타임</li><li><strong>shape</strong> - 플러그인 형태/인터페이스</li></ul><h3 id="실행-시기" tabindex="-1">실행 시기 <a class="header-anchor" href="#실행-시기" aria-label="Permalink to &quot;실행 시기&quot;">​</a></h3><ul><li>plugin-sdk 내보내기 또는 하위 경로 변경 후</li><li>채널 또는 프로바이더 플러그인 추가 또는 수정 후</li><li>플러그인 등록 또는 검색 리팩토링 후</li></ul><p>계약 테스트는 CI에서 실행되며 실제 API 키가 필요하지 않습니다.</p><h2 id="회귀-추가-가이드" tabindex="-1">회귀 추가 (가이드) <a class="header-anchor" href="#회귀-추가-가이드" aria-label="Permalink to &quot;회귀 추가 (가이드)&quot;">​</a></h2><p>라이브에서 발견된 프로바이더/모델 문제를 수정할 때:</p><ul><li>가능하면 CI 안전 회귀를 추가하십시오 (모의/스텁 프로바이더, 또는 정확한 요청 형태 변환 캡처)</li><li>본질적으로 라이브 전용인 경우 (속도 제한, 인증 정책), 라이브 테스트를 좁게 유지하고 환경 변수를 통해 선택 사항으로 만드십시오</li><li>버그를 포착하는 가장 작은 레이어를 대상으로 하십시오: <ul><li>프로바이더 요청 변환/리플레이 버그 → 직접 모델 테스트</li><li>게이트웨이 세션/히스토리/도구 파이프라인 버그 → 게이트웨이 라이브 스모크 또는 CI 안전 게이트웨이 모의 테스트</li></ul></li></ul>',62)])])}const m=l(d,[["render",t]]);export{h as __pageData,m as default};
